def avg_after_boost(spec: dict) -> float:
    """Average reachable value after boosting nodes at or above the cut."""
    adj = spec["adj"]; vals = dict(spec["vals"])
    start = spec["start"]; cut = spec["cut"]; bonus = spec["bonus"]
    seen = []
    queue = [start]
    while queue:
        n = queue.pop(0)
        if n in seen:
            continue
        seen.append(n)
        queue.extend(adj[n])
    for n in seen:
        if vals[n] >= cut:
            vals[n] += bonus
    total = 0
    for n in seen:
        total += vals[n]
    return round(total / len(seen), 2)
