def repost_chain(spec: dict) -> str:
    """Follow the repost chain from the start post, '>'-joined; the smallest id wins when several repost it."""
    posts = set(spec["posts"])
    if spec["start"] not in posts:
        return ""
    children = {}
    for r in spec["reposts"]:
        if r[0] in posts and r[1] in posts:
            children.setdefault(r[1], []).append(r[0])
    chain = [spec["start"]]
    seen = {spec["start"]}
    cur = spec["start"]
    while True:
        nxt = sorted(c for c in children.get(cur, []) if c not in seen)
        if not nxt:
            break
        cur = nxt[0]
        chain.append(cur)
        seen.add(cur)
    return ">".join(chain)
